// 三载体一致：纯 JS、无 DOM/uplink/shadow 足迹
import jStatModule from 'https://cdn.jsdelivr.net/npm/jstat@1/+esm';
const jStat = jStatModule.jStat ?? jStatModule;
const operation = data.operation ?? 'pdf';
const input = operation === 'inv' ? data.p : (operation === 'pdf' || operation === 'cdf' ? data.x : undefined);
const args = input === undefined ? data.params : [input, ...data.params];
const result = jStat[data.distribution][operation](...args);
